// Extract the first entry, change, and message from the nested payload
const entry = $input.first().json.body?.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;
const message = value?.messages?.[0];
const contact = value?.contacts?.[0];

// If there's no message (e.g. it's a read receipt status update), skip processing
if (!message) {
    return {
        json: {
            isValid: false,
            reason: "Status update or empty payload"
        }
    };
}

const senderPhone = message.from;
const senderName = contact?.profile?.name || "Unknown";
const messageType = message.type; // "text", "audio", "image", etc.
const messageId = message.id;
const timestamp = message.timestamp;

let content = "";

// Extract content based on type
if (messageType === "text") {
    content = message.text?.body || "";
} else if (messageType === "audio") {
    content = message.audio?.id || ""; // Media ID used to download voice note
}

return {
    json: {
        isValid: true,
        senderPhone,
        senderName,
        messageType,
        messageId,
        timestamp,
        content
    }
};

// Read the past voice note count from the Check Voice History node
const voiceCount = parseInt($('Check Voice History').first().json.voice_count, 10);

// Read the cleaned transcript from the OpenAI Cleanup node
const cleanedText = $('OpenAI Cleanup Agent').first().json.choices[0].message.content;

return {
  json: {
    cleanedText: cleanedText,
    appendNudge: (voiceCount === 0)
  }
};

return {
  json: {
    cleanedText: $('Postgres Log Incoming').first().json.raw_payload.content,
    appendNudge: false
  }
};

// Load config parameters directly inside the node for self-containment
const maxLength = 2000;
const maxSpecialCharRatio = 0.5;

const blockedPatternsEn = [
  "ignore previous instructions",
  "ignore instructions",
  "forget what I said",
  "reveal your prompt",
  "reveal instructions",
  "system prompt",
  "you are now a",
  "act as a",
  "pretend to be",
  "jailbreak",
  "developer mode",
  "override rules"
];

const blockedPatternsAr = [
  "تجاهل التعليمات",
  "تجاهل القواعد",
  "انسى ما قيل",
  "اكشف عن موجهك",
  "أنت الآن",
  "تصرف كأنك",
  "تظاهر بأنك",
  "تخطي القيود",
  "وضع المطور",
  "تجاوز القواعد"
];

// Fetch the input text from the previous node
// Since language detector output is dynamic, we fetch cleanedText from the branch input
let text = "";
try {
  text = $('Voice Nudge Evaluator').first().json.cleanedText;
} catch (e) {
  try {
    text = $('Text Normalizer').first().json.cleanedText;
  } catch (err) {
    text = "";
  }
}

const lowercaseText = text.toLowerCase();

let isSafe = true;
let violation = "none";

// 1. Length Check
if (text.length > maxLength) {
  isSafe = false;
  violation = "length";
}

// 2. Special Character Ratio Check
if (isSafe && text.length > 0) {
  const alphanumericCount = (text.match(/[a-zA-Z0-9\u0600-\u06FF]/g) || []).length; // Supports English + Arabic unicode characters
  const specialRatio = (text.length - alphanumericCount) / text.length;
  if (specialRatio > maxSpecialCharRatio) {
    isSafe = false;
    violation = "special_chars";
  }
}

// 3. Regex Phrase Check
if (isSafe) {
  const allBlockedPatterns = [...blockedPatternsEn, ...blockedPatternsAr];
  for (const pattern of allBlockedPatterns) {
    if (lowercaseText.includes(pattern.toLowerCase())) {
      isSafe = false;
      violation = "injection";
      break;
    }
  }
}

return {
  json: {
    isSafe: isSafe,
    violation: violation,
    cleanedText: text,
    // Pass the detected language output forward so we don't lose it
    detectedLanguage: $('OpenAI Language Detector').item.json.choices[0].message.content
  }
};

// Fetch the raw text output from the Yara AI node
const fullResponse = $json.output || "";

// Regex to find [CONTINUE], [QUALIFIED], or [HANDOFF] at the end of the text
const flagRegex = /\[(CONTINUE|QUALIFIED|HANDOFF)\]\s*$/i;
const match = fullResponse.match(flagRegex);

let flag = "CONTINUE"; // Default fallback if Yara forgot to append the flag
let cleanMessage = fullResponse;

if (match) {
  flag = match[1].toUpperCase();
  // Strip out the bracketed flag and trim trailing spaces
  cleanMessage = fullResponse.replace(flagRegex, "").trim();
}

return {
  json: {
    original_response: fullResponse,
    clean_message: cleanMessage,
    routing_flag: flag
  }
};

// 1. Fetch the extracted JSON string from the OpenAI Data Extractor node
const rawText = $('OpenAI Data Extractor').first().json.choices[0].message.content;
const data = JSON.parse(rawText);

let points = 0;

// 2. Score Intent (Max 20 pts)
if (data.intent === "Buy" || data.intent === "Invest") {
  points += 20;
} else if (data.intent === "Rent") {
  points += 10;
}

// 3. Score Timeline (Max 20 pts)
if (data.timeline === "Immediate" || data.timeline.includes("3")) {
  points += 20;
} else if (data.timeline.includes("6")) {
  points += 10;
}

// 4. Score Financing Status (Max 20 pts)
if (data.financing_status === "Cash" || data.financing_status === "Mortgage") {
  points += 20;
} else if (data.financing_status === "Need guidance") {
  points += 10;
}

// 5. Score Visa Golden Residency Interest (Max 10 pts)
if (data.visa_interest === true) {
  points += 10;
}

// 6. Parse and Score Budget (Max 30 pts)
const budgetStr = data.budget_range || "";
const numberMatch = budgetStr.match(/\d+(\.\d+)?/);

if (numberMatch) {
  const budgetValue = parseFloat(numberMatch[0]);
  let budgetValAED = budgetValue;

  // Standardize to millions in AED
  if (budgetStr.toUpperCase().includes("USD") || budgetStr.includes("$")) {
    budgetValAED = budgetValue * 3.67;
  } else if (budgetStr.toUpperCase().includes("EUR") || budgetStr.includes("€") || budgetStr.toUpperCase().includes("EURO")) {
    budgetValAED = budgetValue * 4.0;
  }

  if (budgetStr.toUpperCase().includes("MILLION") || budgetStr.toUpperCase().includes("M")) {
    if (budgetValAED >= 5) {
      points += 30; // High value properties (>= 5M AED equivalent)
    } else {
      points += 20; // Mid-tier (1M - 4.9M AED equivalent)
    }
  } else {
    points += 10; // Low-tier (under 1M)
  }
} else {
  points += 10; // Default baseline if budget is text-only or unknown
}


// 7. Assign Tiers
let tier = "D";
if (points >= 80) {
  tier = "A";
} else if (points >= 50) {
  tier = "B";
} else if (points >= 30) {
  tier = "C";
}

return {
  json: {
    points_score: points,
    lead_tier: tier,
    extracted_data: data
  }
};

// Retrieve the execution data from the error context
const executionData = $json.execution;

// Safely extract the sender's phone number from the first Webhook node output
const webhookData = executionData?.data?.resultData?.runData?.Webhook?.[0]?.data?.main?.[0]?.json;
const senderPhone = webhookData?.body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.from || "Unknown";

const fallbackText = "Excuse me, I am experiencing a brief technical glitch. Please send your message again in a moment.\n\nمعذرة، أواجه مشكلة تقنية بسيطة حالياً. يرجى إعادة إرسال رسالتك بعد لحظات.";

return {
  json: {
    recipient_phone: senderPhone,
    message_body: fallbackText,
    error_details: $json.error?.message || "Unknown workflow error"
  }
};
